/**
 * @typedef { {
 *   name: string,
 *   info: string,
 *   type?: 'function',
 *   params?: Array<{
 *     name: string;
 *     type: string;
 *   }>
 *   return: {
 *     type: string;
 *   }
 * } } Builtin
 */

/**
 * @typedef {Omit<Builtin, 'params' | 'return'> & {
 *   params?: Array<{
 *     name: string;
 *   }>
 * }} RawBuiltin
 */

